/// Character display width: 0 (zero-width), 1 (narrow), or 2 (wide).
///
/// For codepoints beyond U+2FFFF, returns 1 (narrow) as the default.
/// Ambiguous-width characters return 1 (narrow) in this function;
/// use `char_width_cjk` for CJK mode where ambiguous = 2.
#[inline]
pub const fn char_width(c: char) -> usize {
    let cp = c as u32;
    if cp >= 0x30000 {
        // CJK Unified Ideographs Extension G (U+30000-U+3134A) and
        // Extension H (U+31350-U+323AF) are East Asian Width "W" (#7775).
        if cp <= 0x323AF {
            return 2;
        }
        return 1; // Beyond table range: default to narrow
    }
    let block_idx = WIDTH_LEVEL1[(cp >> 8) as usize] as usize;
    let offset = (cp & 0xFF) as usize;
    let byte_idx = block_idx * 64 + offset / 4;
    let shift = (offset % 4) * 2;
    let raw = (WIDTH_LEVEL2[byte_idx] >> shift) & 0x03;
    match raw {
        0 => 0, // zero-width
        1 => 1, // narrow
        2 => 2, // wide
        3 => 1, // ambiguous -> narrow (default mode)
        _ => unreachable!(),
    }
}

/// Character display width in CJK mode (ambiguous = 2).
#[inline]
pub const fn char_width_cjk(c: char) -> usize {
    let cp = c as u32;
    if cp >= 0x30000 {
        // CJK Unified Ideographs Extension G/H are wide (#7775).
        if cp <= 0x323AF {
            return 2;
        }
        return 1;
    }
    let block_idx = WIDTH_LEVEL1[(cp >> 8) as usize] as usize;
    let offset = (cp & 0xFF) as usize;
    let byte_idx = block_idx * 64 + offset / 4;
    let shift = (offset % 4) * 2;
    let raw = (WIDTH_LEVEL2[byte_idx] >> shift) & 0x03;
    match raw {
        0 => 0,
        1 => 1,
        2 => 2,
        3 => 2, // ambiguous -> wide (CJK mode)
        _ => unreachable!(),
    }
}

/// Display width of a string (sum of character widths).
///
/// Equivalent to `unicode_width::UnicodeWidthStr::width(s)`.
#[inline]
pub fn str_width(s: &str) -> usize {
    s.chars().map(char_width).sum()
}

/// Display width of a string in CJK mode (ambiguous = 2).
#[inline]
pub fn str_width_cjk(s: &str) -> usize {
    s.chars().map(char_width_cjk).sum()
}

/// Whether a character has East Asian Ambiguous width.
#[inline]
pub const fn is_ambiguous_width(c: char) -> bool {
    let cp = c as u32;
    if cp >= 0x30000 {
        return false;
    }
    let block_idx = WIDTH_LEVEL1[(cp >> 8) as usize] as usize;
    let offset = (cp & 0xFF) as usize;
    let byte_idx = block_idx * 64 + offset / 4;
    let shift = (offset % 4) * 2;
    let raw = (WIDTH_LEVEL2[byte_idx] >> shift) & 0x03;
    raw == 3
}
